/**
 * @param {string} s
 * @param {number} k
 * @return {character}
 */
var processStr = function(s, k) {
    let len = 0;

    for (const char of s) {
        if (char === '*') {
            if (len > 0) {
                len--;
            }
        } else if (char === '#') {
            len *= 2;
        } else if (char === '%') {
            // do nothing
        } else {
            len++;
        }
    }

    if (k >= len) {
        return '.';
    }

    for (let i = s.length - 1; i >= 0; i--) {
        const char = s[i];

        if (char === '*') {
            len++;
        } else if (char === '#') {
            if (k > (len - 1) / 2) {
                k -= Math.floor(len / 2);
            }
            len = Math.floor((len + 1) / 2);
        } else if (char === '%') {
            k = len - 1 - k;
        } else {
            if (k === len - 1) {
                return char;
            }
            len--;
        }
    }

    return '.';
};

/**
 * @param {string} s
 * @param {number} k
 * @return {character}
 */
var processStr = function(s, k) {
    let res = '';
    let reversed = false;

    for (const char of s) {
        if (char === '*') {
            if (reversed) {
                res = res.slice(1);
            } else {
                res = res.slice(0, res.length - 1);
            }
        } else if (char === '#') {
            res = res + res;
        } else if (char === '%') {
            reversed = !reversed;
        } else {
            if (reversed) {
                res = char + res;
            } else {
                res += char;
            }
        }
    }

    return (reversed ? res[res.length - 1 - k] : res[k]) || '.';
};
